sql:
SELECT unit_class_name, movement_range
FROM unit_classes
WHERE movement_range > 5;

SELECT building_id, building_name
FROM buildings
WHERE production_bonus > (SELECT AVG(production_bonus) FROM buildings);

SELECT b.gold_bonus
FROM buildings b
WHERE b.building_id > 5 AND b.tech_id = 10;

SELECT u.unit_name, u.movement_range, uc.unit_class_name
FROM units u
JOIN unit_classes uc ON u.unit_class_id = uc.unit_class_id;

SELECT era_name, start_year
FROM eras
ORDER BY start_year DESC;

SELECT tt.tech_id, tt.parent_tech_id
FROM technology_tree tt
WHERE tt.parent_tech_id IS NOT NULL;

SELECT icon_atlas, audio_intro_header
FROM audio_visuals
WHERE audio_visual_id > 5;

external_knowledge:
- Recent past: Here, it refers to the years after 2000; 
- Early 21st century: Starting from the year 2001;
- Start of the second decade: Refers to the year 2010;
- Notable enough to appear more than twice: Indicates that the era name should occur more than two times in the records, suggesting significance or repetition in the context of the given time frame.

sql:
SELECT COUNT(*)
FROM units
WHERE defense_power > 10;

SELECT AVG(movement_range) AS average_movement_range
FROM unit_classes
WHERE attack_power > 10;

SELECT 
  (SELECT SUM(attack_power) FROM unit_classes) + 
  (SELECT MAX(healing_rate) FROM features) AS total_sum;

SELECT unit_name, unit_id
FROM units
WHERE attack_power > (SELECT AVG(attack_power) FROM units);

SELECT u.unit_name
FROM units u
WHERE u.unit_class_id = 1 AND u.attack_power > (
    SELECT AVG(attack_power)
    FROM unit_classes
);

SELECT diplomacy_id, effect_name, tech_id
FROM diplomacy
WHERE effect_value > 5;

SELECT COUNT(tech_id) 
FROM prerequisites 
WHERE prerequisite_unit IS NULL;
